function parseRange(s) {
  if (typeof s !== 'string') return undefined;
  const m = s.match(/^(-?\d+)(?:-(-?\d+))?$/);
  if (!m) return undefined;
  if (m[2] !== undefined) {
    const a = parseInt(m[1], 10);
    const b = parseInt(m[2], 10);
    const out = [];
    if (a <= b) {
      for (let i = a; i <= b; i++) out.push(i);
    } else {
      for (let i = a; i >= b; i--) out.push(i);
    }
    return out;
  }
  return [parseInt(m[1], 10)];
}
